INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-consultant-rules-tr', 'cp-consultant-rules', 'tr', 'Danışman Kuralları ve Etik İlkeler', 'danisman-kurallari', '{"html": "<h2>Danışman Kuralları ve Etik İlkeler</h2><h3>1. Genel İlke</h3><p>Gold Mood Astro’da hizmet sunan tüm danışmanlar, kullanıcı güvenliğini, dürüst iletişimi ve etik danışmanlık ilkelerini kabul eder. Danışmanlar sundukları içeriklerden ve kullanıcılarla kurdukları iletişimden bizzat sorumludur.</p><h3>2. Hizmetin Amacı</h3><p>Danışmanlık hizmetleri yalnızca kişisel farkındalık, kişisel gelişim, sembolik yorum, kişisel değerlendirme ve eğlence amacıyla sunulabilir.</p><h3>3. Yasaklı Beyanlar</h3><p>Danışmanların aşağıdaki ifadeleri kullanması yasaktır:</p><ul><li>kesin olacak</li><li>yüzde yüz sonuç</li><li>garanti dönüş</li><li>seni kesin evlendireceğim</li><li>onu kesin geri döndüreceğim</li><li>kesin para kazanacaksın</li><li>hastalığın şudur</li><li>ilaç kullan</li><li>dava aç</li><li>şu hisseyi al</li><li>şu kriptoyu al</li><li>şu bahse oyna</li><li>büyü yaparım</li><li>büyü bozarım</li><li>bağlama yaparım</li><li>ritüel ile çözerim</li></ul><h3>4. Yasaklı Hizmetler</h3><p>Danışmanlar aşağıdaki hizmetleri sunamaz:</p><ul><li>büyü</li><li>büyü bozma</li><li>bağlama ritüeli</li><li>muska hazırlama</li><li>cin çıkarma</li><li>ruh çağırma</li><li>medyumluk adı altında garanti vaatleri</li><li>kesin ilişki döndürme</li><li>kesin evlilik garantisi</li><li>kesin para kazanma garantisi</li><li>bahis tahmini</li><li>şans oyunu tahmini</li><li>yatırım tavsiyesi</li><li>sağlık teşhisi</li><li>ilaç veya tedavi önerisi</li><li>hukuki danışmanlık</li><li>vergi danışmanlığı</li><li>yasa dışı herhangi bir faaliyet</li></ul><h3>5. Platform Dışına Yönlendirme Yasağı</h3><p>Danışmanlar kullanıcıları Platform dışına yönlendiremez. Danışmanların kullanıcılarla aşağıdaki bilgileri paylaşması yasaktır:</p><ul><li>telefon numarası</li><li>WhatsApp</li><li>Telegram</li><li>Instagram</li><li>e-posta</li><li>internet sitesi</li><li>IBAN</li><li>banka hesabı</li><li>ödeme linki</li><li>başka platform hesabı</li></ul><h3>6. Korku ve Baskı Yasağı</h3><p>Danışmanlar kullanıcıya korku, panik veya baskı oluşturarak hizmet satamaz. Aşağıdaki tarzda ifadeler yasaktır:</p><ul><li>bunu yaptırmazsan kötü olur</li><li>hemen ek hizmet alman gerekiyor</li><li>üzerinde kötü enerji var</li><li>ödeme yapmazsan düzelmez</li><li>seni kurtarmam için tekrar seans almalısın</li></ul><h3>7. Sağlık, Hukuk ve Finans Sınırı</h3><p>Danışmanlar sağlık, hukuk, vergi, finans, yatırım, psikoloji veya psikiyatri alanlarında profesyonel tavsiye veremez. Bu konularda kullanıcılar ilgili uzmanlara yönlendirilmelidir.</p><h3>8. Moderasyon ve Denetim</h3><p>Gold Mood Astro, danışman profillerini, hizmet açıklamalarını, mesajları, yorumları ve görüşme süreçlerine ait kayıt/metadataları kalite, güvenlik ve mevzuata uyum amacıyla denetleyebilir. Kurallara aykırılık halinde Platform; içeriği kaldırabilir, danışman profilini askıya alabilir, danışmanın hizmetlerini durdurabilir veya danışman hesabını kalıcı olarak kapatabilir.</p><h3>9. Vergisel Sorumluluk</h3><p>Danışmanlar, Platformdan elde ettikleri gelirlerle ilgili tüm vergi, beyan, makbuz, fatura veya gider pusulası süreçlerinden yürürlükteki mevzuat kapsamında sorumludur.</p><h3>10. Kabul</h3><p>Danışman, Gold Mood Astro’da hizmet sunmaya başlayarak bu kuralları okuduğunu, anladığını ve kabul ettiğini beyan eder.</p>"}', 'Danışmanlar için etik ilkeler ve yasaklı beyan/hizmetler.', 'Danışman Kuralları — Gold Mood Astro', 'Gold Mood Astro danışman kuralları ve etik ilkeler.'),
  ('cpi-consultant-rules-en', 'cp-consultant-rules', 'en', 'Consultant Rules and Ethics', 'consultant-rules', '{"html": "<h2>Consultant Rules and Ethics</h2><h3>1. General Principle</h3><p>All consultants on Gold Mood Astro accept user safety, honest communication and ethical consulting principles, and are personally responsible for their content and communication with users.</p><h3>2. Purpose</h3><p>Consulting may be offered only for personal awareness, personal development, symbolic interpretation, personal reflection and entertainment.</p><h3>3. Prohibited Statements</h3><p>Consultants must not use statements such as: definite outcomes, one-hundred-percent results, guaranteed reunions, promises to certainly marry someone, guaranteed money, medical diagnoses, medication advice, instructions to file lawsuits, specific stock/crypto/betting tips, or offers of spells, spell-breaking, binding or ritual solutions.</p><h3>4. Prohibited Services</h3><p>Consultants may not provide spells, spell-breaking, binding rituals, amulets, exorcism, spirit-calling, guaranteed promises under the guise of mediumship, guaranteed relationship reunion/marriage/money, betting or games-of-chance tips, investment advice, medical diagnosis, medication/treatment advice, legal or tax advice, or any unlawful activity.</p><h3>5. No Off-Platform Redirection</h3><p>Consultants may not direct users off the Platform, nor share phone numbers, WhatsApp, Telegram, Instagram, email, websites, IBAN, bank accounts, payment links or other platform accounts.</p><h3>6. No Fear or Pressure</h3><p>Consultants may not sell by creating fear, panic or pressure (e.g. “bad things will happen if you don’t”, “you must buy an add-on now”, “there is negative energy on you”, “it won’t improve unless you pay”, “you must book again for me to save you”).</p><h3>7. Health, Legal and Finance Limits</h3><p>Consultants may not give professional advice in health, legal, tax, finance, investment, psychology or psychiatry; users should be referred to relevant professionals.</p><h3>8. Moderation</h3><p>Gold Mood Astro may review consultant profiles, service descriptions, messages, reviews and session records/metadata for quality, safety and legal compliance. On breach, the Platform may remove content, suspend the profile, stop the consultant’s services or permanently close the account.</p><h3>9. Tax Responsibility</h3><p>Consultants are responsible for all tax, declaration, receipt, invoice or self-employment-voucher processes for income earned via the Platform, under applicable law.</p><h3>10. Acceptance</h3><p>By starting to provide services, the consultant declares having read, understood and accepted these rules.</p>"}', 'Ethics and prohibited statements/services for consultants.', 'Consultant Rules — Gold Mood Astro', 'Gold Mood Astro consultant rules and ethics.'),
  ('cpi-consultant-rules-de', 'cp-consultant-rules', 'de', 'Beraterregeln und Ethik', 'beraterregeln', '{"html": "<h2>Beraterregeln und Ethik</h2><h3>1. Grundsatz</h3><p>Alle Berater akzeptieren Nutzersicherheit, ehrliche Kommunikation und ethische Beratungsgrundsätze und sind für ihre Inhalte und Kommunikation selbst verantwortlich.</p><h3>2. Zweck</h3><p>Beratung darf nur zu Zwecken persönlicher Achtsamkeit, Entwicklung, symbolischer Deutung, Reflexion und Unterhaltung angeboten werden.</p><h3>3. Verbotene Aussagen</h3><p>Verboten sind u. a.: sichere Ergebnisse, hundertprozentige Resultate, garantierte Rückkehr/Heirat, garantierter Geldgewinn, medizinische Diagnosen, Medikamentenempfehlungen, Aufforderungen zu Klagen, konkrete Aktien-/Krypto-/Wett-Tipps sowie Angebote von Zauber, Zauberauflösung, Bindung oder Ritualen.</p><h3>4. Verbotene Leistungen</h3><p>Nicht erlaubt: Zauber, Zauberauflösung, Bindungsrituale, Amulette, Exorzismus, Geisterbeschwörung, garantierte Versprechen unter dem Deckmantel von Medialität, garantierte Beziehungs-/Heirats-/Geldergebnisse, Wett- oder Glücksspieltipps, Anlageberatung, medizinische Diagnose, Medikamenten-/Behandlungsempfehlung, Rechts- oder Steuerberatung sowie rechtswidrige Tätigkeiten.</p><h3>5. Keine Weiterleitung außerhalb der Plattform</h3><p>Berater dürfen Nutzer nicht außerhalb der Plattform leiten und keine Telefonnummern, WhatsApp, Telegram, Instagram, E-Mail, Websites, IBAN, Bankkonten, Zahlungslinks oder andere Plattformkonten teilen.</p><h3>6. Keine Angst oder Druck</h3><p>Verkauf durch Angst, Panik oder Druck ist untersagt.</p><h3>7. Grenzen zu Gesundheit, Recht und Finanzen</h3><p>Keine professionelle Beratung in Gesundheit, Recht, Steuern, Finanzen, Anlage, Psychologie oder Psychiatrie; Verweis an Fachleute.</p><h3>8. Moderation</h3><p>Gold Mood Astro kann Profile, Beschreibungen, Nachrichten, Bewertungen und Sitzungsdaten/Metadaten prüfen. Bei Verstoß: Entfernen von Inhalten, Sperren des Profils, Stoppen der Leistungen oder dauerhafte Kontoschließung.</p><h3>9. Steuerliche Verantwortung</h3><p>Berater sind für alle steuerlichen Prozesse ihrer Einnahmen selbst verantwortlich.</p><h3>10. Zustimmung</h3><p>Mit Aufnahme der Tätigkeit erklärt der Berater, diese Regeln akzeptiert zu haben.</p>"}', 'Ethik und verbotene Aussagen/Leistungen für Berater.', 'Beraterregeln — Gold Mood Astro', 'Gold Mood Astro Beraterregeln und Ethik.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), content = VALUES(content),
  summary = VALUES(summary), meta_title = VALUES(meta_title), meta_description = VALUES(meta_description);

