INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-prohibited-tr', 'cp-prohibited', 'tr', 'Yasaklı Hizmetler Politikası', 'yasakli-hizmetler', '{"html": "<h2>Yasaklı Hizmetler Politikası</h2><p>Gold Mood Astro aşağıdaki hizmetlerin Platform üzerinde sunulmasına, tanıtılmasına, satılmasına veya ima edilmesine izin vermez.</p><h3>1. Büyü, Ritüel ve Medyumluk İçerikleri</h3><ul><li>kara büyü</li><li>büyü</li><li>büyü bozma</li><li>bağlama büyüsü</li><li>ayırma büyüsü</li><li>muska hazırlama</li><li>cin çıkarma</li><li>ruh çağırma</li><li>ritüel ile sonuç garantisi</li><li>medyumluk adı altında kesin vaatler</li></ul><h3>2. Garanti Sonuç Vaatleri</h3><ul><li>kesin ilişki döndürme</li><li>kesin evlilik garantisi</li><li>kesin çocuk sahibi olma garantisi</li><li>kesin iş bulma garantisi</li><li>kesin para kazanma garantisi</li><li>kesin başarı garantisi</li><li>yüzde yüz sonuç garantisi</li></ul><h3>3. Sağlık ve Tedavi İçerikleri</h3><ul><li>sağlık teşhisi</li><li>hastalık yorumu</li><li>ilaç önerisi</li><li>reçete önerisi</li><li>psikiyatrik tedavi</li><li>terapi yerine geçecek yönlendirme</li><li>tıbbi müdahale tavsiyesi</li></ul><h3>4. Hukuk, Vergi ve Finans İçerikleri</h3><ul><li>hukuki danışmanlık</li><li>dava yönlendirmesi</li><li>vergi danışmanlığı</li><li>yatırım tavsiyesi</li><li>hisse senedi önerisi</li><li>kripto para önerisi</li><li>al-sat sinyali</li><li>finansal kazanç garantisi</li></ul><h3>5. Bahis ve Şans Oyunu İçerikleri</h3><ul><li>bahis tahmini</li><li>maç sonucu tahmini</li><li>şans oyunu tahmini</li><li>piyango tahmini</li><li>kumar yönlendirmesi</li></ul><h3>6. Yasa Dışı İçerikler</h3><ul><li>dolandırıcılık</li><li>tehdit</li><li>şantaj</li><li>kişisel verilerin izinsiz paylaşılması</li><li>yasa dışı ödeme talebi</li><li>üçüncü kişilere zarar vermeye yönelik yönlendirme</li><li>yürürlükteki mevzuata aykırı her türlü faaliyet</li></ul><h3>7. Yaptırım</h3><p>Gold Mood Astro, yasaklı hizmet veya içerik tespit ettiğinde; içeriği kaldırabilir, hizmeti yayından kaldırabilir, danışman hesabını askıya alabilir, kullanıcı hesabını askıya alabilir, üyeliği kalıcı olarak sonlandırabilir ve gerekli hallerde yetkili mercilere bildirimde bulunabilir.</p>"}', 'Platformda sunulması yasak hizmet ve içerikler.', 'Yasaklı Hizmetler Politikası — Gold Mood Astro', 'Gold Mood Astro yasaklı hizmetler politikası.'),
  ('cpi-prohibited-en', 'cp-prohibited', 'en', 'Prohibited Services Policy', 'prohibited-services', '{"html": "<h2>Prohibited Services Policy</h2><p>Gold Mood Astro does not allow the following to be offered, promoted, sold or implied on the Platform.</p><h3>1. Spells, Rituals and Mediumship</h3><ul><li>black magic</li><li>spells</li><li>spell-breaking</li><li>binding spells</li><li>separation spells</li><li>amulets</li><li>exorcism</li><li>spirit-calling</li><li>guaranteed results via rituals</li><li>definite promises under the guise of mediumship</li></ul><h3>2. Guaranteed-Outcome Promises</h3><ul><li>guaranteed relationship reunion</li><li>guaranteed marriage</li><li>guaranteed conception</li><li>guaranteed employment</li><li>guaranteed money</li><li>guaranteed success</li><li>one-hundred-percent result guarantees</li></ul><h3>3. Health and Treatment</h3><ul><li>medical diagnosis</li><li>disease interpretation</li><li>medication advice</li><li>prescription advice</li><li>psychiatric treatment</li><li>guidance replacing therapy</li><li>medical-intervention advice</li></ul><h3>4. Legal, Tax and Finance</h3><ul><li>legal advice</li><li>litigation guidance</li><li>tax advice</li><li>investment advice</li><li>stock tips</li><li>crypto tips</li><li>buy-sell signals</li><li>financial-gain guarantees</li></ul><h3>5. Betting and Games of Chance</h3><ul><li>betting tips</li><li>match-result tips</li><li>games-of-chance tips</li><li>lottery tips</li><li>gambling guidance</li></ul><h3>6. Unlawful Content</h3><ul><li>fraud</li><li>threats</li><li>blackmail</li><li>unauthorized sharing of personal data</li><li>unlawful payment demands</li><li>guidance to harm third parties</li><li>any activity contrary to applicable law</li></ul><h3>7. Enforcement</h3><p>On detecting prohibited services or content, Gold Mood Astro may remove the content, unpublish the service, suspend the consultant or user account, permanently terminate membership, and report to competent authorities where necessary.</p>"}', 'Services and content prohibited on the Platform.', 'Prohibited Services Policy — Gold Mood Astro', 'Gold Mood Astro prohibited services policy.'),
  ('cpi-prohibited-de', 'cp-prohibited', 'de', 'Richtlinie zu verbotenen Leistungen', 'verbotene-leistungen', '{"html": "<h2>Richtlinie zu verbotenen Leistungen</h2><p>Gold Mood Astro erlaubt nicht, dass die folgenden Leistungen angeboten, beworben, verkauft oder angedeutet werden.</p><h3>1. Zauber, Rituale und Medialität</h3><ul><li>schwarze Magie</li><li>Zauber</li><li>Zauberauflösung</li><li>Bindungszauber</li><li>Trennungszauber</li><li>Amulette</li><li>Exorzismus</li><li>Geisterbeschwörung</li><li>garantierte Ergebnisse durch Rituale</li><li>sichere Versprechen unter dem Deckmantel von Medialität</li></ul><h3>2. Garantieversprechen</h3><ul><li>garantierte Beziehungsrückkehr</li><li>garantierte Heirat</li><li>garantierte Empfängnis</li><li>garantierte Anstellung</li><li>garantierter Geldgewinn</li><li>garantierter Erfolg</li><li>100%-Ergebnisgarantien</li></ul><h3>3. Gesundheit und Behandlung</h3><ul><li>medizinische Diagnose</li><li>Krankheitsdeutung</li><li>Medikamentenempfehlung</li><li>Rezeptempfehlung</li><li>psychiatrische Behandlung</li><li>Therapieersatz</li><li>Empfehlung medizinischer Eingriffe</li></ul><h3>4. Recht, Steuern und Finanzen</h3><ul><li>Rechtsberatung</li><li>Prozessführung</li><li>Steuerberatung</li><li>Anlageberatung</li><li>Aktientipps</li><li>Krypto-Tipps</li><li>Kauf-/Verkaufssignale</li><li>Gewinngarantien</li></ul><h3>5. Wetten und Glücksspiel</h3><ul><li>Wetttipps</li><li>Spielergebnistipps</li><li>Glücksspieltipps</li><li>Lotterietipps</li><li>Glücksspielförderung</li></ul><h3>6. Rechtswidrige Inhalte</h3><ul><li>Betrug</li><li>Drohungen</li><li>Erpressung</li><li>unbefugte Weitergabe personenbezogener Daten</li><li>rechtswidrige Zahlungsforderungen</li><li>Anleitung zur Schädigung Dritter</li><li>jede rechtswidrige Tätigkeit</li></ul><h3>7. Durchsetzung</h3><p>Bei Feststellung kann Gold Mood Astro Inhalte entfernen, Leistungen sperren, Berater- oder Nutzerkonten sperren, die Mitgliedschaft beenden und ggf. Behörden informieren.</p>"}', 'Auf der Plattform verbotene Leistungen und Inhalte.', 'Verbotene Leistungen — Gold Mood Astro', 'Gold Mood Astro Richtlinie zu verbotenen Leistungen.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), content = VALUES(content),
  summary = VALUES(summary), meta_title = VALUES(meta_title), meta_description = VALUES(meta_description);
